     4→import { http, bypass, HttpResponse } from 'msw';
     5→import { extractMockSchemas, GetHeaders } from '../transport';
     6→import { matchSchemas } from '../request-matcher/utils';
     7→import { ResponseBuilder } from '../response-builder';
     8→
     9→export function createHandler(getIncomingHeaders: GetHeaders) {
    10→  return http.all('*', async ({ request }) => {
    11→    const mockSchemas = await extractMockSchemas(getIncomingHeaders);
    12→    const matchResult = await matchSchemas(request, mockSchemas);
    13→    if (!matchResult) return;
    14→
    15→    const { body, headers, status, statusText } = await new ResponseBuilder(matchResult, {
    16→      bypass: (req) => fetch(bypass(req)),
    17→    }).build();
    18→
    19→    return new HttpResponse(body, { status, statusText, headers });
    20→  });
    21→}
