     1→/**
     2→ * MockClient class.
     3→ */
     4→import {
     5→  MockRequestSchema,
     6→  MockRequestSchemaInit,
     7→  MockResponseSchemaInit,
     8→  MockSchema,
     9→  buildMockRequestSchema,
    10→  buildMockResponseSchema,
    11→  toMockRequestSchemaObject,
    12→} from '../protocol';
    13→import { buildMockHeaders } from '../transport';
    14→import { mergeOptions } from './utils';
    15→
    16→export type MockClientOptions = {
    17→  debug?: boolean;
    18→  defaultMethod?: MockRequestSchema['method'];
    19→};
    20→
    21→export type MockRequestSchemaNoMethod = Omit<MockRequestSchemaInit, 'method'>;
    22→
    23→export class MockClient {
    24→  private mockSchemas = new Map<MockRequestSchemaInit, MockSchema>();
    25→  public headers: Record<string, string> = {};
    26→  public onChange?: (headers: Record<string, string>) => unknown;
    27→
    28→  constructor(protected options?: MockClientOptions) {}
    29→
    30→  get schemas() {
    31→    return [...this.mockSchemas.values()];
    32→  }
    33→
    34→  async addMock(reqSchema: MockRequestSchemaInit, resSchema: MockResponseSchemaInit) {
    35→    const mockSchema = {
    36→      reqSchema: this.buildRequestSchema(reqSchema),
    37→      resSchema: this.buildResponseSchema(resSchema),
    38→    };
    39→    this.mockSchemas.set(reqSchema, mockSchema);
    40→    await this.rebuildHeaders();
    41→  }
    42→
    43→  async GET(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    44→    return this.addMockWithMethod('GET', reqSchema, resSchema);
    45→  }
    46→
    47→  async POST(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    48→    return this.addMockWithMethod('POST', reqSchema, resSchema);
    49→  }
    50→
    51→  async PUT(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    52→    return this.addMockWithMethod('PUT', reqSchema, resSchema);
    53→  }
    54→
    55→  async DELETE(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    56→    return this.addMockWithMethod('DELETE', reqSchema, resSchema);
    57→  }
    58→
    59→  async HEAD(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    60→    return this.addMockWithMethod('HEAD', reqSchema, resSchema);
    61→  }
    62→
    63→  async ALL(reqSchema: MockRequestSchemaNoMethod, resSchema: MockResponseSchemaInit) {
    64→    return this.addMockWithMethod(undefined, reqSchema, resSchema);
    65→  }
    66→
    67→  async reset() {
    68→    this.mockSchemas.clear();
    69→    await this.rebuildHeaders();
    70→  }
    71→
    72→  private addMockWithMethod(
    73→    method: MockRequestSchema['method'],
    74→    reqSchema: MockRequestSchemaNoMethod,
    75→    resSchema: MockResponseSchemaInit,
    76→  ) {
    77→    const initObj = toMockRequestSchemaObject(reqSchema as MockRequestSchemaInit);
    78→    return this.addMock({ ...initObj, method }, resSchema);
    79→  }
    80→
    81→  private async rebuildHeaders() {
    82→    this.headers = buildMockHeaders(this.schemas);
    83→    await this.onChange?.(this.headers);
    84→  }
    85→
    86→  private buildRequestSchema(init: MockRequestSchemaInit) {
    87→    const initObj = toMockRequestSchemaObject(init);
    88→    const { defaultMethod: method, debug } = this.options || {};
    89→    const initObjWithDefaults = mergeOptions({ method, debug }, initObj);
    90→    return buildMockRequestSchema(initObjWithDefaults);
    91→  }
    92→
    93→  private buildResponseSchema(init: MockResponseSchemaInit) {
    94→    // place to apply defaults
    95→    return buildMockResponseSchema(init);
    96→  }
    97→}
