     4→import { MockSchema } from '../protocol';
     5→import { HeadersLike, toHeaders } from './utils';
     6→
     7→const MOCK_HEADER = 'x-mock-request';
     8→
     9→type Maybe<T> = T | undefined;
    10→export type GetHeaders = () => Maybe<HeadersLike> | Promise<Maybe<HeadersLike>>;
    11→
    12→export function buildMockHeaders(mockSchemas: MockSchema[]) {
    13→  return { [MOCK_HEADER]: JSON.stringify(mockSchemas) };
    14→}
    15→
    16→export async function extractMockSchemas(getHeaders: GetHeaders) {
    17→  const headersLike = await getHeaders();
    18→  if (!headersLike) return;
    19→
    20→  const headers = toHeaders(headersLike);
    21→  try {
    22→    const mockingHeader = headers.get(MOCK_HEADER);
    23→    if (!mockingHeader) return;
    24→
    25→    return JSON.parse(mockingHeader) as MockSchema[];
    26→  } catch {
    27→    // do nothing
    28→  }
    29→}
