     1→/**
     2→ * Playwright interceptor.
     3→ * Used in Playwright tests to mock page requests with the same syntax as for server requests.
     4→ */
     5→
     6→import { Page, BrowserContext, Request as PwRequest, Route } from '@playwright/test';
     7→import { matchSchemas } from '../request-matcher/utils';
     8→import { ResponseBuilder } from '../response-builder';
     9→import { MockClient } from '../client';
    10→
    11→export async function setupPlaywrightInterceptor(
    12→  page: Page | BrowserContext,
    13→  mockClient: MockClient,
    14→) {
    15→  await page.route('**', async (route) => {
    16→    const request = buildFetchRequest(route.request());
    17→    const matchResult = await matchSchemas(request, mockClient.schemas);
    18→    if (!matchResult) return route.fallback();
    19→
    20→    const { body, headers, status } = await new ResponseBuilder(matchResult, {
    21→      bypass: (req) => bypass(req, route),
    22→    }).build();
    23→
    24→    await route.fulfill({
    25→      status,
    26→      headers: Object.fromEntries(headers),
    27→      body: body instanceof ArrayBuffer ? Buffer.from(body) : (body ?? undefined),
    28→      // route.fulfill() doesn't accept statusText
    29→    });
    30→  });
    31→}
    32→
    33→function buildFetchRequest(pwRequest: PwRequest) {
    34→  return new Request(pwRequest.url(), {
    35→    method: pwRequest.method(),
    36→    headers: pwRequest.headers(),
    37→    body: pwRequest.postDataBuffer(),
    38→  });
    39→}
    40→
    41→async function bypass(req: Request, route: Route) {
    42→  const pwResponse = await route.fetch({
    43→    url: req.url,
    44→    headers: Object.fromEntries(req.headers),
    45→    postData: req.body ? Buffer.from(await req.arrayBuffer()) : undefined,
    46→  });
    47→
    48→  return {
    49→    status: pwResponse.status(),
    50→    statusText: pwResponse.statusText(),
    51→    headers: new Headers(pwResponse.headers()),
    52→    arrayBuffer: () => pwResponse.body(),
    53→    json: () => pwResponse.json(),
    54→  };
    55→}
