     1→import { RequestMatcher } from '.';
     2→import { MockMatchResult, MockSchema } from '../protocol';
     3→
     4→export async function matchSchemas(
     5→  req: Request,
     6→  mockSchemas: MockSchema[] = [],
     7→): Promise<MockMatchResult | undefined> {
     8→  for (const mockSchema of mockSchemas) {
     9→    const debug = mockSchema.reqSchema.debug || mockSchema.resSchema.debug;
    10→    const matcher = new RequestMatcher(mockSchema.reqSchema, debug);
    11→    const result = await matcher.match(req);
    12→    if (result) {
    13→      return { mockSchema, req: req, params: result };
    14→    }
    15→  }
    16→}
