     1→/**
     2→ * Schema to generate the response.
     3→ */
     4→
     5→// serializable
     6→export type MockResponseSchema = {
     7→  /**
     8→   * The HTTP status code, default is 200.
     9→   */
    10→  status?: number;
    11→  /**
    12→   * The response headers, defined as key-value pairs.
    13→   */
    14→  headers?: Record<string, string>;
    15→  /**
    16→   * The response body, defined as a string or JSON.
    17→   */
    18→  body?: string | null | Record<string, unknown> | Array<unknown>;
    19→  /**
    20→   * The response body patch, defined as a key-value pairs.
    21→   * If defined, the real request will be sent, and the response will be patched.
    22→   * Not compatible with the 'body' field.
    23→   */
    24→  bodyPatch?: Record<string, string | number | boolean | null>;
    25→  /**
    26→   * Request overrides.
    27→   * If defined, the real request will be sent with the overrides.
    28→   * Not compatible with the 'body' field.
    29→   */
    30→  request?: {
    31→    /**
    32→     * The new URL to send the real request.
    33→     */
    34→    url?: string;
    35→    /**
    36→     * The new request query params, defined as key-value pairs.
    37→     */
    38→    query?: Record<string, string | number | null>;
    39→    /**
    40→     * The new request headers, defined as key-value pairs.
    41→     */
    42→    headers?: Record<string, string | null>;
    43→    /**
    44→     * The new request body, defined as a string or JSON.
    45→     */
    46→    body?: string | null | Record<string, unknown> | Array<unknown>;
    47→    /**
    48→     * The new request body patch, defined as a key-value pairs.
    49→     */
    50→    bodyPatch?: Record<string, string | number | boolean | null>;
    51→  };
    52→  /**
    53→   * The delay in milliseconds before sending the response.
    54→   */
    55→  delay?: number;
    56→  /**
    57→   * Flag to output debug info on server.
    58→   */
    59→  debug?: boolean;
    60→};
    61→
    62→export type MockRequestOverrides = NonNullable<MockResponseSchema['request']>;
    63→export type MockResponseSchemaInit = number | MockResponseSchema;
    64→
    65→export function buildMockResponseSchema(init: MockResponseSchemaInit): MockResponseSchema {
    66→  const initObj = toMockResponseSchemaObject(init);
    67→  assertSchema(initObj);
    68→
    69→  return Object.assign({}, initObj);
